#!/usr/bin/env node
import { promises as fs } from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = path.resolve(__dirname, "..", "..");
const CONTENT_ROOT = path.join(REPO_ROOT, "client", "src", "data", "blog-content");
const LANGS = ["es", "en", "fr", "de", "pt", "ca"];

const HEADER = `// AUTO-GENERATED by scripts/blog/generate-content-bundles.mjs
// Do not edit manually. Re-run \`node scripts/blog/generate-content-bundles.mjs\`
// after adding/removing files in client/src/data/blog-content/<lang>/.
//
// One bundle per language. Keys are the canonical Spanish slug. Values are the
// raw markdown string of the localized article. Used by server/static.ts to
// emit a localized SEO prerender for crawlers per <html lang> URL.
`;

async function listSlugs(lang) {
  const dir = path.join(CONTENT_ROOT, lang);
  const entries = await fs.readdir(dir);
  return entries
    .filter((f) => f.endsWith(".ts") && !f.startsWith("."))
    .map((f) => f.replace(/\.ts$/, ""))
    .sort();
}

async function generateBundle(lang, { writeMode }) {
  const slugs = await listSlugs(lang);
  const constName = `BLOG_CONTENT_${lang.toUpperCase()}`;
  const imports = slugs.map((s, i) => `import c${i} from './${lang}/${s}';`).join("\n");
  const entries = slugs.map((s, i) => `"${s}": c${i},`).join("\n");
  const out = `${HEADER}\n${imports}\n\nexport const ${constName}: Record<string, string> = {\n${entries}\n};\n`;
  const target = path.join(CONTENT_ROOT, `${lang}-all.ts`);
  let prev = "";
  try { prev = await fs.readFile(target, "utf8"); } catch { /* missing */ }
  const changed = prev !== out;
  if (changed && writeMode) await fs.writeFile(target, out, "utf8");
  return { lang, slugs: slugs.length, changed };
}

async function main() {
  const checkOnly = process.argv.includes("--check");
  const results = [];
  for (const lang of LANGS) results.push(await generateBundle(lang, { writeMode: !checkOnly }));
  const total = results.reduce((s, r) => s + r.slugs, 0);
  const changed = results.filter((r) => r.changed);
  console.log(`blog-content bundles${checkOnly ? " [check mode]" : ""}:`);
  for (const r of results) {
    const status = r.changed ? (checkOnly ? "(STALE)" : "(updated)") : "(unchanged)";
    console.log(`  ${r.lang}-all.ts: ${r.slugs} slugs ${status}`);
  }
  console.log(`Total entries across 6 bundles: ${total}. ${checkOnly ? `Stale: ${changed.length}/${LANGS.length}.` : `Files updated: ${changed.length}/${LANGS.length}.`}`);
  if (checkOnly && changed.length > 0) {
    console.error(`\n[ERROR] ${changed.length} bundle(s) out of sync with client/src/data/blog-content/<lang>/.`);
    console.error("[ERROR] Run: node scripts/blog/generate-content-bundles.mjs");
    process.exit(2);
  }
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
